var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어, 어떻게 하죠? 작전상 후퇴하나?","JPN":"ど、どうしましょう？　戦略的撤退？","ENG":"W-what do we do? Make a strategic retreat?","TWN":"怎、怎麼辦？要戰略性撤退嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"글쎄, 저 군침 흘리는 표정을 보면 순순히 도망치도록 놔두진 않을 것 같은데......","JPN":"どうかな。あのヨダレを垂れ流した表情を見るに、おとなしく見逃してくれそうもないけど……","ENG":"She seems to be drooling over us, doesn't she? I don't think she's going to casually let us go.","TWN":"這個嘛，看她口水直流的表情，應該不會乖乖放我們逃走吧……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그보다는 손이라도 흔들어 보면 어때? 오랜만에 만난 딸인데 혹시 살려줄지도 모르잖아?","JPN":"それより、手でも振ってみたら？\\n久しぶりに会った娘なんだから、もしかしたら殺さないでくれるかもよ？","ENG":"Why don't you give her a wave? Maybe she'll change her mind after the long-awaited reunion.","TWN":"不然向她揮揮手怎麼樣？妳是她好久不見的女兒，說不定她會放我們一條生路呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저건 제 어머니가 아니라 괴물이에요!","JPN":"あれはお母様ではなく、怪物です！","ENG":"That's a monster in my mother's body, not my mother herself!","TWN":"那不是我母親，是怪物！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고...... 진짜 어머니라고 해도 절 그렇게 반가워하시진 않을걸요.","JPN":"それに……本当にお母様だったとしても、私に会っても喜ばないと思いますわ。","ENG":"Besides, even if it were my mother, I doubt she'd be pleased to see me anyway.","TWN":"而且……就算是真的母親，見到我應該也不會太高興吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"도망치세요 레지나 님.","JPN":"逃げてください、レジーナ様。","ENG":"Run, Miss Regina.","TWN":"請逃走吧，蕾佳娜大人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델?","JPN":"エデル？","ENG":"Edel?","TWN":"艾瑟兒？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희가 시간을 벌게요. 그 사이에 도망치시면 돼요.","JPN":"我々が時間を稼ぎます。その間に逃げるのです。","ENG":"We'll buy you time. Get to safety while we stall her.","TWN":"我們會爭取時間。您就趁機逃跑吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"무슨 바보 같은 소리에요?! 에델도 같이 가야죠!","JPN":"なにバカなことを言っているのですか！？　エデルも一緒に行きましょう！","ENG":"What are you talking about? You're coming with us, Edel!","TWN":"妳在說什麼傻話？！艾瑟兒也要一起走啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럴 수 없어요. 레지나 님.","JPN":"それはできません、レジーナ様。","ENG":"We can't, Miss Regina.","TWN":"我們不能那麼做，蕾佳娜大人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"비록 반쪽 짜리이긴 해도, 저희는 에크하르트 초월지식 학회의 학회장이에요.","JPN":"たとえ臨時とはいえ、我々はエクハルト超越知識学会の学会長です。","ENG":"Although only half qualified, I, along with these babies, am the President of Eckhart's\xA0Society\xA0for\xA0Preternatural\xA0Research.","TWN":"就算是個半吊子，我們也是埃克哈特超越知識學會的學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그리고 갈라진 지식의 호수를 하나로 만드는 것이 학회장인 저희의 의무랍니다.","JPN":"そして、割れた知識の湖を一つにすることが学会長である我々の義務なのです。","ENG":"And as the President, I'm obligated to collect all the pieces of the Lake of Knowledge together.","TWN":"而且，將分裂的知識湖水合而為一，是作為學會長的義務。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저것과 싸우겠다고요? 승산이 전혀 없잖아요!","JPN":"あれと戦うつもりですか？　勝ち目はありませんよ！","ENG":"You're going to fight that thing? You don't stand a chance!","TWN":"妳要和那東西戰鬥？這完全沒有勝算吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 건 상관없어요. 지식의 호수는 반드시 하나가 되어야 하니까요.","JPN":"そんなことは関係ありません。知識の湖は必ず一つにならなければなりませんから。","ENG":"It doesn't matter. The Lake of Knowledge must become whole.","TWN":"沒關係。因為知識之湖必須合為一體。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"설령...... 저희가 잡아 먹히는 쪽이 되더라도.","JPN":"たとえ……我々が食われる側になったとしても。","ENG":"Even though it means that we're going to be the one that's being swallowed.","TWN":"就算……就算我們被吃掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님.","JPN":"レジーナ様。","ENG":"Miss Regina.","TWN":"蕾佳娜大人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님은 좋은 학회장이 되실 거에요.","JPN":"レジーナ様は良い学会長になられるでしょう。","ENG":"You'll make the great President of the Society.","TWN":"蕾佳娜大人一定會成為一位優秀的學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러니 가세요.","JPN":"ですから、行ってください。","ENG":"So go.","TWN":"所以請快走吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그리고 언젠가 이 아이들이 지닌 지식을 계승할 때까지......","JPN":"そして、いつかこの子たちの持つ知識を継承する時まで……","ENG":"And please stay alive...","TWN":"並且，在繼承那些孩子們持有的知識之前……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"꼭 살아남아 주세요.","JPN":"必ず生き残ってください。","ENG":"until you inherit the knowledge of these babies.","TWN":"請一定要活下去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"짧은 시간이었지만 레지나 님을 만나서 정말로 즐거웠어요.","JPN":"短い時間でしたが、レジーナ様にお会いできて本当に楽しかったです。","ENG":"It hasn't been long, but it's been a pleasure knowing you.","TWN":"雖然相處的時間很短暫，但遇見蕾佳娜大人，我們真的很高興。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럼...... 이만.","JPN":"では……これで。","ENG":"Then, farewell.","TWN":"那就……再見了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};